import{_ as t,o as r,c as s,a2 as i}from"./chunks/framework.Cuq8tsM6.js";const v=JSON.parse('{"title":"Audience & Score","description":"","frontmatter":{"title":"Audience & Score"},"headers":[],"relativePath":"docs/fr/publishers/audience-setup.md","filePath":"docs/fr/publishers/audience-setup.md"}'),o={name:"docs/fr/publishers/audience-setup.md"};function a(n,e,l,d,c,u){return r(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="configuration-de-l-audience-score" tabindex="-1">Configuration de l&#39;Audience &amp; Score <a class="header-anchor" href="#configuration-de-l-audience-score" aria-label="Permalink to &quot;Configuration de l&#39;Audience &amp; Score&quot;">​</a></h1><p>Votre fiche audience est votre vitrine auprès des annonceurs. Plus elle est précise, plus vous recevrez de propositions pertinentes.</p><h2 id="_1-l-identite-de-votre-audience" tabindex="-1">1. L&#39;Identité de votre Audience <a class="header-anchor" href="#_1-l-identite-de-votre-audience" aria-label="Permalink to &quot;1. L&#39;Identité de votre Audience&quot;">​</a></h2><p>C&#39;est la première chose que l&#39;annonceur voit. Soignez la présentation pour déclencher le &quot;coup de cœur&quot;.</p><ul><li><strong>Présentation :</strong> Racontez votre histoire, vos valeurs et votre positionnement.</li><li><strong>Engagements RSE :</strong> Cochez les cases (Made in France, Colis réutilisables...) uniquement si vous pouvez le prouver.</li><li><strong>Visuels :</strong> Uploadez un logo et une bannière qui représentent votre univers.</li></ul><div class="gi-accent-box"><strong>💡 Le conseil de l&#39;équipe</strong><p style="margin:0.5rem 0 0;">Dans le champ <strong>&quot;Persona&quot;</strong>, soyez descriptif : <em>&quot;Jardinier amateur ou expert cherchant des produits durables pour entretenir son potager.&quot;</em> Cela aide les annonceurs à mieux comprendre qui sont vos clients.</p></div><h2 id="_2-les-donnees-demographiques-data" tabindex="-1">2. Les Données Démographiques (Data) <a class="header-anchor" href="#_2-les-donnees-demographiques-data" aria-label="Permalink to &quot;2. Les Données Démographiques (Data)&quot;">​</a></h2><p>Ces champs alimentent l&#39;algorithme de getinside pour le matching.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>Panier Moyen</strong><p>Indiquez le montant HT moyen. Cela permet aux annonceurs de cibler par pouvoir d&#39;achat.</p></div><div class="gi-value-card"><strong>Typologie (B2C/B2B)</strong><p>Critère excluant. Assurez-vous qu&#39;il est correct.</p></div><div class="gi-value-card"><strong>Profil d&#39;acheteur</strong><p><em>Discounter, Économe, Médian, Élevé.</em> Positionnez-vous par rapport à votre marché.</p></div></div><h2 id="_3-comprendre-votre-score-distributeur" tabindex="-1">3. Comprendre votre &quot;Score Distributeur&quot; <a class="header-anchor" href="#_3-comprendre-votre-score-distributeur" aria-label="Permalink to &quot;3. Comprendre votre &quot;Score Distributeur&quot;&quot;">​</a></h2><div class="gi-accent-box"><div style="display:flex;align-items:center;gap:1.25rem;margin-bottom:1rem;"><div style="font-size:2.5rem;font-weight:800;line-height:1;color:var(--vp-c-brand-1);">4,3<span style="font-size:1.125rem;font-weight:400;color:var(--vp-c-text-2);">/5</span></div><div><strong style="display:block;margin-bottom:0.2rem;">Votre passeport pour plus de campagnes</strong><span style="font-size:0.8125rem;color:var(--vp-c-text-2);">Ce score est recalculé dynamiquement selon 7 critères clés. Il détermine votre position dans les résultats de recherche.</span></div></div><div style="background:var(--vp-c-bg-elv);border-radius:6px;padding:0.875rem 1rem;"><strong style="display:block;margin-bottom:0.5rem;font-size:0.875rem;">Barème de visibilité :</strong><ul style="margin:0;padding-left:1.25rem;font-size:0.8125rem;color:var(--vp-c-text-2);"><li style="margin-bottom:0.25rem;"><span style="color:var(--gi-tint-red-text);">●</span> <strong>Moins de 3/5 :</strong> Audience peu visible. Des actions correctives sont nécessaires.</li><li style="margin-bottom:0.25rem;"><span style="color:var(--gi-tint-yellow-text);">●</span> <strong>De 3 à 4/5 :</strong> Visibilité standard. Vous recevez des propositions régulièrement.</li><li><span style="color:var(--gi-tint-green-text);">●</span> <strong>Plus de 4/5 :</strong> Statut &quot;Top Distributeur&quot;. Vous apparaissez en priorité et obtenez le badge de confiance.</li></ul></div></div><h3 id="detail-des-7-criteres-de-notation" tabindex="-1">Détail des 7 critères de notation <a class="header-anchor" href="#detail-des-7-criteres-de-notation" aria-label="Permalink to &quot;Détail des 7 critères de notation&quot;">​</a></h3><div class="gi-value-grid"><div class="gi-value-card"><strong>💰 Tarification</strong><p>L&#39;algorithme compare votre CPM (Coût Pour Mille) à la moyenne du marché sur votre secteur. Un prix cohérent booste ce score.</p></div><div class="gi-value-card"><strong>📈 Volume semaine (Reach)</strong><p>Plus votre capacité de diffusion est importante et stable, plus ce score est élevé. Les volumes trop faibles peuvent impacter la note.</p></div><div class="gi-value-card"><strong>✨ Attractivité de la marque</strong><p>Reflète la notoriété et la perception de votre enseigne. Plus votre marque est identifiée comme une référence sur son marché, plus ce score est élevé.</p></div><div class="gi-value-card"><strong>📦 Fiabilité de l&#39;inventaire</strong><p>Respectez-vous les volumes promis ? Si vous distribuez moins que prévu sans prévenir, ce score chute drastiquement.</p></div><div class="gi-value-card"><strong>⚡ Réactivité de l&#39;audience</strong><p>Mesure la performance de vos campagnes passées (taux de scan, usage codes promo). Une audience engagée qui réagit aux offres fait monter ce score.</p></div><div class="gi-value-card"><strong>📊 Historique de campagne</strong><p>Récompense la fidélité. Ce score augmente mécaniquement avec le nombre de campagnes réussies sur la plateforme.</p></div><div class="gi-value-card"><strong>💬 Communication &amp; Reporting</strong><p>Évalue votre sérieux opérationnel : rapidité de réponse aux demandes (sous 48h) et envoi des preuves de distribution dans les délais.</p></div></div>',13)])])}const m=t(o,[["render",a]]);export{v as __pageData,m as default};
